 336→
 337→interface ClientsProps {
 338→  onBack: () => void;
 339→  onNavigate: (view: string) => void;
 340→  user: { name: string; email: string; plan: 'free' | 'pro' | 'enterprise'; credits: number } | null;
 341→  directClientCount: number;
 342→  maxClients: number;
 343→}
 344→
 345→const MISSION_STATUS_LABELS: Record<string, { label: string; color: string }> = {
 346→  nouveau: { label: 'Nouveau', color: 'text-blue-400 bg-blue-500/10 border-blue-500/20' },
 347→  accepte: { label: 'Accepté', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20' },
 348→  en_cours: { label: 'En cours', color: 'text-amber-400 bg-amber-500/10 border-amber-500/20' },
 349→  termine: { label: 'Terminé', color: 'text-green-400 bg-green-500/10 border-green-500/20' },
 350→  refuse: { label: 'Refusé', color: 'text-red-400 bg-red-500/10 border-red-500/20' },
 351→};
 352→
 353→const getScoreColor = (score: number) => {
 354→  if (score >= 70) return 'text-green-400';
 355→  if (score >= 50) return 'text-yellow-400';
 356→  if (score >= 30) return 'text-orange-400';
 357→  return 'text-red-400';
 358→};
 359→
 360→const Clients: React.FC<ClientsProps> = ({ onBack, onNavigate, user, directClientCount, maxClients }) => {
 361→  const [clients, setClients] = useState<Client[]>(ALL_INITIAL_CLIENTS);
 362→  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
 363→  const [searchTerm, setSearchTerm] = useState('');
 364→  const [statusFilter, setStatusFilter] = useState('all');
 365→  const [sourceFilter, setSourceFilter] = useState<'all' | 'direct' | 'mission'>('all');
 366→  const [showNewClientModal, setShowNewClientModal] = useState(false);
 367→  const [showLimitAlert, setShowLimitAlert] = useState(false);
 368→
 369→  useEffect(() => {
 370→    if (showLimitAlert || showNewClientModal) { document.body.style.overflow = 'hidden'; }
 371→    return () => { document.body.style.overflow = ''; };
 372→  }, [showLimitAlert, showNewClientModal]);
 373→
 374→  // Compteur de clients directs ajoutés manuellement (excluant les clients mission)
 375→  const addedDirectClients = useMemo(() => clients.filter(c => c.source === 'direct').length, [clients]);
 376→  const totalDirectCount = directClientCount + addedDirectClients - DIRECT_CLIENTS.length; // nouveaux directs ajoutés cette session + ceux du mois
 377→  const isAtLimit = totalDirectCount >= maxClients && user?.plan !== 'enterprise';
 378→  const planLabel = user?.plan === 'free' ? 'Starter' : user?.plan === 'pro' ? 'Pro' : 'Agency';
 379→
 380→  // New client form state
 381→  const [newClient, setNewClient] = useState({
 382→    companyName: '',
 383→    contactName: '',
 384→    email: '',
 385→    phone: '',
 386→    role: '',
 387→    plan: 'Starter' as 'Starter' | 'Pro' | 'Agency',
 388→    address: '',
 389→    siret: '',
 390→    vatNumber: '',
 391→  });
 392→
 393→  const filteredClients = useMemo(() => {
 394→    return clients.filter(client => {
 395→      const matchesSearch = client.companyName.toLowerCase().includes(searchTerm.toLowerCase()) ||
 396→                            client.contactName.toLowerCase().includes(searchTerm.toLowerCase()) ||
 397→                            client.email.toLowerCase().includes(searchTerm.toLowerCase());
 398→      const matchesStatus = statusFilter === 'all' || client.status === statusFilter;
 399→      const matchesSource = sourceFilter === 'all' || client.source === sourceFilter;
 400→      return matchesSearch && matchesStatus && matchesSource;
 401→    });
 402→  }, [clients, searchTerm, statusFilter, sourceFilter]);
 403→
 404→  const totalMRR = useMemo(() => clients.reduce((acc, curr) => curr.status === 'active' ? acc + curr.mrr : acc, 0), [clients]);
 405→  const activeCount = useMemo(() => clients.filter(c => c.status === 'active').length, [clients]);
 406→  const missionClientCount = useMemo(() => clients.filter(c => c.source === 'mission').length, [clients]);
 407→
 408→  // --- EXPORT CSV ---
 409→  const handleExportCSV = () => {
 410→    const headers = [
 411→      'ID', 'Entreprise', 'Contact', 'Rôle', 'Email', 'Téléphone',
 412→      'Statut', 'Plan', 'MRR (€)', 'Source', 'Date création',
 413→      'Cycle facturation', 'Méthode paiement', 'SLA',
 414→      'Adresse', 'SIRET', 'TVA', 'Pays',
 415→      'Mission ID', 'URL analysée', 'Score AEO', 'Budget mission (€)', 'Statut mission', 'Deadline mission'
 416→    ];
 417→
 418→    const rows = filteredClients.map(c => [
 419→      c.id,
 420→      c.companyName,
 421→      c.contactName,
 422→      c.role,
 423→      c.email,
 424→      c.phone,
 425→      c.status,
 426→      c.plan,
 427→      c.mrr,
 428→      c.source,
 429→      c.createdAt,
 430→      c.contract.billingCycle,
 431→      c.contract.paymentMethod,
 432→      c.contract.slaLevel,
 433→      c.legal.address,
 434→      c.legal.siret,
 435→      c.legal.vatNumber,
 436→      c.legal.country,
 437→      c.mission?.missionId || '',
 438→      c.mission?.analyzedUrl || '',
 439→      c.mission?.aeoScore || '',
 440→      c.mission?.budget || '',
 441→      c.mission?.missionStatus || '',
 442→      c.mission?.deadline || '',
 443→    ]);
 444→
 445→    const csvContent = [
 446→      headers.join(';'),
 447→      ...rows.map(row => row.map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(';'))
 448→    ].join('\n');
 449→
 450→    // BOM for Excel UTF-8 compatibility
 451→    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
 452→    const url = URL.createObjectURL(blob);
 453→    const link = document.createElement('a');
 454→    link.href = url;
 455→    link.download = `citedby-clients-${new Date().toISOString().slice(0, 10)}.csv`;
 456→    document.body.appendChild(link);
 457→    link.click();
 458→    document.body.removeChild(link);
 459→    URL.revokeObjectURL(url);
 460→  };
 461→
 462→  // --- TENTATIVE OUVERTURE MODAL ---
 463→  const handleOpenNewClient = () => {
 464→    if (isAtLimit) {
 465→      setShowLimitAlert(true);
 466→      return;
 467→    }
 468→    setShowNewClientModal(true);
 469→  };
 470→
 471→  // --- ADD NEW CLIENT ---
 472→  const handleAddClient = () => {
 473→    if (!newClient.companyName.trim() || !newClient.contactName.trim() || !newClient.email.trim()) return;
 474→
 475→    const id = `C-${String(clients.length + 1).padStart(3, '0')}`;
 476→    const avatar = newClient.contactName
 477→      .split(' ')
 478→      .map(n => n.charAt(0).toUpperCase())
 479→      .slice(0, 2)
 480→      .join('');
 481→
 482→    const client: Client = {
 483→      id,
 484→      companyName: newClient.companyName,
 485→      contactName: newClient.contactName,
 486→      email: newClient.email,
 487→      phone: newClient.phone || '-',
 488→      role: newClient.role || '-',
 489→      status: 'pending',
 490→      plan: newClient.plan,
 491→      mrr: 0,
 492→      avatar,
 493→      source: 'direct',
 494→      createdAt: new Date().toISOString().slice(0, 10),
 495→      contract: {
 496→        startDate: '-',
 497→        renewalDate: '-',
 498→        billingCycle: 'Mensuel',
 499→        paymentMethod: 'Stripe (CB)',
 500→        slaLevel: 'Standard',
 501→        nextInvoiceAmount: 0,
 502→      },
 503→      legal: {
 504→        address: newClient.address || '-',
 505→        vatNumber: newClient.vatNumber || 'En attente',
 506→        siret: newClient.siret || 'En attente',
 507→        country: 'France',
 508→      },
 509→    };
 510→
 511→    setClients(prev => [client, ...prev]);
 512→    setShowNewClientModal(false);
 513→    setNewClient({ companyName: '', contactName: '', email: '', phone: '', role: '', plan: 'Starter', address: '', siret: '', vatNumber: '' });
 514→  };
 515→
 516→  // --- RENDER DETAIL VIEW ---
 517→  if (selectedClient) {
 518→    const m = selectedClient.mission;
 519→    const mStatusConf = m ? MISSION_STATUS_LABELS[m.missionStatus] : null;
 520→
 521→    return (
 522→      <div className="w-full px-6 py-8 animate-in fade-in slide-in-from-right duration-300">
 523→        <button
 524→          onClick={() => setSelectedClient(null)}
 525→          className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors group"
 526→        >
 527→          <ArrowLeft size={18} className="mr-2 group-hover:-translate-x-1 transition-transform" />
 528→          Retour à la base clients
 529→        </button>
 530→
 531→        {/* Header Fiche Client */}
 532→        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
 533→          <div className="flex items-center gap-4">
 534→            <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-gray-800 to-black border border-white/[0.08] flex items-center justify-center text-white font-bold text-2xl shadow-inner">
 535→              {selectedClient.avatar}
 536→            </div>
 537→            <div>
 538→              <h1 className="text-3xl font-sans font-bold text-white mb-1">{selectedClient.companyName}</h1>
 539→              <div className="flex items-center gap-3 flex-wrap">
 540→                <span className="text-sm text-gray-500 flex items-center gap-1">
 541→                  <Building2 size={14} /> {selectedClient.id}
 542→                </span>
 543→                <span className={`px-2 py-0.5 text-xs font-bold rounded-full border ${
 544→                  selectedClient.status === 'active' ? 'bg-purple-500/10 border-white/[0.1] text-purple-300' :
 545→                  selectedClient.status === 'pending' ? 'bg-amber-500/10 border-amber-500/20 text-amber-400' :
 546→                  'bg-red-500/10 border-red-500/20 text-red-400'
 547→                }`}>
 548→                  {selectedClient.status === 'active' ? 'Actif' : selectedClient.status === 'pending' ? 'En attente' : 'Inactif'}
 549→                </span>
 550→                <span className={`px-2 py-0.5 text-[10px] font-semibold rounded-full border ${
 551→                  selectedClient.source === 'mission'
 552→                    ? 'bg-orange-500/10 border-orange-500/20 text-orange-400'
 553→                    : 'bg-white/5 border-white/10 text-gray-500'
 554→                }`}>
 555→                  {selectedClient.source === 'mission' ? 'Via Mission' : 'Client direct'}
 556→                </span>
 557→              </div>
 558→            </div>
 559→          </div>
 560→          <div className="flex gap-3">
 561→            <button className="px-4 py-2 bg-white/[0.04] border border-white/[0.08] hover:bg-purple-500/10 rounded-full text-sm font-medium text-white transition-colors flex items-center gap-2">
 562→              <Download size={16} /> Factures
 563→            </button>
 564→            <button className="px-4 py-2 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-full hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center gap-2">
 565→              <FileText size={16} /> Éditer Contrat
