 17→const CREDIT_COST_TXT = 3;
 18→const CREDIT_COST_JSON = 5;
 19→
 20→type ActiveTab = 'llms-txt' | 'llm-json';
 21→
 22→const LlmsTxtGenerator: React.FC<Props> = ({ onBack, user, onDeductCredits, history }) => {
 23→  // Active tab
 24→  const [activeTab, setActiveTab] = useState<ActiveTab>('llms-txt');
 25→
 26→  // Form state (shared between both tabs)
 27→  const [siteName, setSiteName] = useState('');
