 44→
 45→  // Result state for llms.txt
 46→  const [isGeneratingTxt, setIsGeneratingTxt] = useState(false);
 47→  const [txtResult, setTxtResult] = useState<{ content: string; sections: number; wordCount: number } | null>(null);
 48→  const [copiedTxt, setCopiedTxt] = useState(false);
