 134→<!-- /wp:html -->`;
 135→  }
 136→  // webflow
 137→  return `<!-- Webflow Embed Block -->
 138→<div class="w-embed citedby-eeat-embed" data-citedby="true" data-eeat-component="true" data-source="citedby-ai">
 139→  <style>
