 147→const ExportPanel: React.FC<{ code: string; title: string }> = ({ code, title }) => {
 148→  const [format, setFormat] = useState<ExportFormat>('html-raw');
 149→  const [copied, setCopied] = useState(false);
 150→
 151→  const formattedCode = wrapForFormat(code, format);
 152→
 153→  const handleCopy = () => {
 154→    navigator.clipboard.writeText(formattedCode);
 155→    setCopied(true);
 156→    setTimeout(() => setCopied(false), 2000);
 157→  };
 158→
 159→  const handleDownload = () => {
 160→    const blob = new Blob([formattedCode], { type: 'text/html' });
 161→    const url = URL.createObjectURL(blob);
 162→    const a = document.createElement('a');
 163→    a.href = url;
 164→    a.download = `${title.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}.html`;
 165→    document.body.appendChild(a);
 166→    a.click();
 167→    document.body.removeChild(a);
 168→    URL.revokeObjectURL(url);
 169→  };
 170→
 171→  const formatOptions: { id: ExportFormat; label: string }[] = [
 172→    { id: 'html-raw', label: 'HTML brut' },
 173→    { id: 'wordpress', label: 'WordPress Shortcode' },
 174→    { id: 'webflow', label: 'Webflow Embed' },
 175→  ];
 176→
 177→  return (
 178→    <div className="ninja-card overflow-hidden">
 179→      <div className="px-4 py-3 border-b border-white/[0.04] space-y-3">
 180→        <div className="flex items-center justify-between">
 181→          <span className="text-xs text-gray-500 font-semibold">{title} - Export CMS</span>
 182→        </div>
 183→        {/* Format selector */}
 184→        <div className="flex gap-1.5">
 185→          {formatOptions.map(opt => (
 186→            <button key={opt.id} onClick={() => setFormat(opt.id)}
 187→              className={`px-3 py-1.5 text-[11px] font-medium rounded-lg transition-all ${
 188→                format === opt.id
 189→                  ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30'
 190→                  : 'bg-white/[0.03] text-gray-500 border border-white/[0.06] hover:text-gray-300'
 191→              }`}>
 192→              {opt.label}
 193→            </button>
 194→          ))}
 195→        </div>
 196→        {/* Action buttons */}
 197→        <div className="flex gap-2">
 198→          <button onClick={handleCopy}
 199→            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-purple-500/10 text-purple-400 border border-purple-500/20 hover:bg-purple-500/20 transition-all">
 200→            {copied ? <Check size={12} /> : <Copy size={12} />}
 201→            {copied ? 'Copie !' : 'Copier HTML'}
 202→          </button>
 203→          <button onClick={handleDownload}
 204→            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-white/[0.04] text-gray-400 border border-white/[0.08] hover:text-gray-200 transition-all">
 205→            <Download size={12} />
 206→            Telecharger .html
 207→          </button>
 208→        </div>
 209→      </div>
 210→      <pre className="p-4 text-xs text-gray-300 overflow-auto max-h-60 custom-scrollbar"><code>{formattedCode}</code></pre>
